// Vérifier qu'on a bien récupéré des utilisateurs
const users = $input.all().map(item => item.json);

if (!users || users.length === 0) {
  throw new Error('Aucun utilisateur trouvé dans la base de données pour les emails spécifiés');
}

console.log(`✅ ${users.length} utilisateur(s) récupéré(s) depuis PostgreSQL`);

const webhookData = $input.first().json;

// Ajouter les informations supplémentaires à chaque utilisateur
const items = users.map(user => ({
  json: {
    ...user,
    triggered_by: webhookData.triggered_by || 'admin@siapet.tn',
    triggered_at: webhookData.triggered_at || new Date().toISOString(),
    demande_url: `${process.env.FRONTEND_URL || 'http://localhost:3000'}/demande-acces`
  }
}));

return items;

const user = $input.item.json;
const role = user.role.toLowerCase();

// Contenu personnalisé selon le rôle
const roleContent = {
  etudiant: {
    title: '🎓 Étudiants',
    benefits: [
      '📚 Suivi de votre parcours académique en temps réel',
      '📊 Consultation de vos notes et résultats',
      '📅 Gestion de vos inscriptions',
      '📄 Accès à vos documents administratifs',
      '💬 Communication directe avec votre établissement'
    ],
    color: '#43e97b',
    gradient: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)'
  },
  enseignant: {
    title: '👨‍🏫 Enseignants',
    benefits: [
      '📊 Gérez vos classes et étudiants efficacement',
      '✍️ Saisissez les notes et évaluations en ligne',
      '📋 Consultez les listes de présence',
      '📈 Analysez les performances de vos étudiants',
      '🗓️ Planifiez vos cours et examens'
    ],
    color: '#4facfe',
    gradient: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)'
  },
  directeur: {
    title: '👔 Directeurs',
    benefits: [
      '📊 Tableau de bord complet de votre établissement',
      '👥 Gestion des enseignants et du personnel',
      '📈 Statistiques et rapports détaillés',
      '🎯 Suivi des performances académiques',
      '📋 Validation des décisions administratives'
    ],
    color: '#f093fb',
    gradient: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)'
  },
  recteur: {
    title: '🎩 Recteurs',
    benefits: [
      '🏛️ Vue d\'ensemble de toute l\'université',
      '📊 Analyses stratégiques et KPIs',
      '👥 Gestion globale des établissements',
      '📈 Rapports consolidés et tendances',
      '🎯 Pilotage de la stratégie universitaire'
    ],
    color: '#667eea',
    gradient: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
  }
};

const content = roleContent[role] || roleContent.etudiant;

console.log(`📧 Personnalisation pour ${user.email} (${role})`);

return {
  json: {
    ...user,
    roleTitle: content.title,
    benefits: content.benefits,
    color: content.color,
    gradient: content.gradient
  }
};

